const SwingEntry& swing_lut_lookup(float detected_period_s) {
    std::size_t best_i = 0;
    float       best_d = std::fabs(SWING_LUT[0].period_s - detected_period_s);
    for (std::size_t i = 1; i < SWING_LUT_SIZE; ++i) {
        float d = std::fabs(SWING_LUT[i].period_s - detected_period_s);
        if (d < best_d) { best_d = d; best_i = i; }
    }
    return SWING_LUT[best_i];
}
